exercises.solution_code:
#include <iostream>

void level2(int v) {
    std::cout << "level2 received " << v << '\n';
}

void level1(int v) {
    std::cout << "level1 received " << v << '\n';
    level2(v);
}

int main() {
    int n{};
    std::cin >> n;
    std::cout << "main received " << n << '\n';
    level1(n);
    return 0;
}

