exercises.solution_code:
#include <iostream>

int main() {
    int n{};
    std::cin >> n;

    int* arr{new int[n]};

    for (int i{0}; i < n; ++i) {
        std::cin >> arr[i];
    }

    int sum{0};
    int positives{0};
    for (int i{0}; i < n; ++i) {
        sum += arr[i];
        if (arr[i] > 0) {
            ++positives;
        }
    }

    std::cout << "sum: " << sum << '\n';
    std::cout << "positives: " << positives << '\n';

    delete[] arr;

    return 0;
}
